+
+func pruneStaleArtifacts(suiteDir string, maxAgeDays int) error {
+	if maxAgeDays <= 0 {
+		return nil
+	}
+	entries, err := os.ReadDir(suiteDir)
+	if err != nil {
+		if errors.Is(err, os.ErrNotExist) {
+			return nil
+		}
+		return err
+	}
+
+	cutoff := time.Now().AddDate(0, 0, -maxAgeDays)
+	for _, entry := range entries {
+		info, err := entry.Info()
+		if err != nil {
+			return err
+		}
+		if info.ModTime().Before(cutoff) {
+			if err := os.RemoveAll(filepath.Join(suiteDir, entry.Name())); err != nil {
+				return err
+			}
+		}
+	}
+	return nil
+}
+
+func appendJSONL(path string, value interface{}) error {
+	data, err := json.Marshal(value)
+	if err != nil {
+		return err
+	}
+	f, err := os.OpenFile(path, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0o644)
+	if err != nil {
+		return err
+	}
+	defer f.Close()
+	_, err = f.WriteString(string(data) + "\n")
+	return err
+}
+
+func sanitizeFilename(s string) string {
+	replacer := strings.NewReplacer(
+		"/", "_",
+		"\\", "_",
+		":", "_",
+		"*", "_",
+		"?", "_",
+		"\"", "_",
+		"<", "_",
+		">", "_",
+		"|", "_",
+		" ", "_",
+		"=", "_",
+	)
+	s = replacer.Replace(s)
+	s = strings.ReplaceAll(s, "-", "_")
+	s = strings.Trim(s, "_.")
+	if s == "" {
+		return "artifact"
+	}
+	return s
+}
+
+func sanitizeSessionComponent(s string) string {
+	var b strings.Builder
+	for _, r := range s {
+		switch {
+		case r >= 'a' && r <= 'z':
+			b.WriteRune(r)
+		case r >= 'A' && r <= 'Z':
+			b.WriteRune(r)
+		case r >= '0' && r <= '9':
+			b.WriteRune(r)
+		case r == '-' || r == '_':
+			b.WriteRune(r)
+		default:
+			b.WriteByte('_')
+		}
+	}
+	out := strings.Trim(b.String(), "_")
+	if out == "" {
+		return "scenario"
+	}
+	return out
+}
+
+func buildSessionName(prefix, name string) string {
+	ordinal := scenarioSequence.Add(1)
+	return fmt.Sprintf(
+		"%s_%s_%s_%03d",
+		sanitizeSessionComponent(prefix),
+		sanitizeSessionComponent(name),
+		time.Now().UTC().Format("20060102_150405"),
+		ordinal,
+	)
+}
